fun solve(n: Long): Boolean {
    var sum = 0L
    var product = 1L
    for (c in n.toString().toCharArray()) {
        val digit = c.toString().toLong()
        sum += digit
        product *= digit
    }
    val total = sum + product
    return n % total == 0L
}
